import { isPositiveFiniteNumber } from '@dexter/tacocat-core';

const getDiscount = (price, priceWithoutDiscount) => {
    if (
        !isPositiveFiniteNumber(price) ||
        !isPositiveFiniteNumber(priceWithoutDiscount)
    )
        return;
    return Math.floor(
        ((priceWithoutDiscount - price) / priceWithoutDiscount) * 100,
    );
};

/**
 * Renders the discount markup
 * @param {PriceContext & PromoPriceContext} context
 * @param {PriceData} value
 * @param {PriceAttributes} attributes
 !* @returns {string} the discount markup
 !*/
const createDiscountTemplate = () => (context, value) => {
    const { price, priceWithoutDiscount } = value;
    const discount = getDiscount(price, priceWithoutDiscount);
    return discount === undefined
        ? `<span class="no-discount"></span>`
        : `<span class="discount">${discount}%</span>`;
};

export { getDiscount, createDiscountTemplate };

import { createDiscountTemplate } from './template.js';

const discount = createDiscountTemplate();

export { discount };

import { expect } from '@esm-bundle/chai';
import {
    getDiscount,
    createDiscountTemplate,
} from '../../src/discount/template.js';

describe('discount template', () => {
    [
        [undefined, undefined, undefined],
        [null, null, undefined],
        ['', '', undefined],
        [50, 100, 50],
        [27, -1, undefined],
        [27, 30, 10],
    ].forEach(([price, priceWithoutDiscount, expected]) =>
        it(`For price=${price} and old price=${priceWithoutDiscount} and the discount percentage is${expect}`, () => {
            expect(getDiscount(price, priceWithoutDiscount)).to.equal(expected);
        }),
    );

    it('Generates discount markup', () => {
        expect(
            createDiscountTemplate()(
                {},
                { price: 27, priceWithoutDiscount: 30 },
            ),
        ).to.equal('<span class="discount">10%</span>');
    });

    it('Generates no discount markup', () => {
        expect(createDiscountTemplate()({}, { price: 27 })).to.equal(
            '<span class="no-discount"></span>',
        );
    });
});

// Utilities copied from `@pandora/react-price` library
// https://git.corp.adobe.com/PandoraUI/commerce/tree/master/packages/react-price/src/js/utils/
//      price-util.ts
//      FormatStringHelpers.ts
// import { RecurrenceTerm } from '@pandora/react-price';
import { Commitment, Term } from '../constants.js';
import formatNumber from './numberFormat.js';

const DECIMAL_POINT = '.';
const DECIMAL_COMMA = ',';
const SPACE_START_PATTERN = /^\s+/;
const SPACE_END_PATTERN = /\s+$/;
const NBSP = '&nbsp;';

const getAnnualPrice = (price) => price * 12;

/**
 * Checks if a promotion is currently active.
 *
 * @param {Object} promotion - The promotion object.
 * @param {string} promotion.start - The start date of the promotion in ISO format.
 * @param {string} promotion.end - The end date of the promotion in ISO format.
 * @param {Object} promotion.displaySummary - The display summary of the promotion.
 * @param {number} promotion.displaySummary.amount - The amount of the promotion, (e.g: in percentage).
 * @param {number} promotion.displaySummary.duration - The duration of the promotion.
 * @param {number} promotion.displaySummary.minProductQuantity - The minimum product quantity for the promotion.
 * @param {string} promotion.displaySummary.outcomeType - The outcome type of the promotion.
 * @param {string} [instant] - An optional date string to use as the current date. If not provided, the current date is used.
 * @param {number} quantity - The quantity of the product.
 * @returns {boolean} - Returns true if the promotion is active, false otherwise.
 */
const isPromotionActive = (promotion, instant, quantity = 1) => {
    if (!promotion) return false;
    const {
        start,
        end,
        displaySummary: {
            amount,
            duration,
            minProductQuantity = 1,
            outcomeType,
        } = {},
    } = promotion;
    if (!(amount && duration && outcomeType)) {
        return false;
    }
    if (quantity < minProductQuantity) {
        return false;
    }
    const now = instant ? new Date(instant) : new Date();
    if (!start || !end) {
        return false;
    }

    const startDate = new Date(start);
    const endDate = new Date(end);

    return now >= startDate && now <= endDate;
};

// TODO: @pandora/react-price does not have "module" field in package.json and is bundled entirely by Webpack
const RecurrenceTerm = {
    MONTH: 'MONTH',
    YEAR: 'YEAR',
};

/**
 * Number of months in each commitment term.
 * Used to calculate per-month price for a given term.
 */
const opticalPriceDivisors = {
    [Term.ANNUAL]: 12,
    [Term.MONTHLY]: 1,
    [Term.THREE_YEARS]: 36,
    [Term.TWO_YEARS]: 24,
};

/**
 * Creates and returns a rule for rounding optical prices based on price characteristics.
 * @param { ({ price: number, divisor: number, usePrecision: boolean }) => boolean } accept
 * A function returning true if this rule should be applied to the price being rounded.
 * @param { ({ price: number, divisor: number, usePrecision: boolean }) => number } round
 * A function applying the rule to the price.
 */
const opticalPriceRoundingRule = (accept, round) => ({ accept, round });

/**
 * List of rules for rounding optical prices.
 * The first rule accepting the price will round it.
 */
const opticalPriceRoundingRules = [
    opticalPriceRoundingRule(
        // optical price for the term is a multiple of the initial price
        ({ divisor, price }) => price % divisor == 0,
        ({ divisor, price }) => price / divisor,
    ),
    opticalPriceRoundingRule(
        // round optical price up to 2 decimals
        ({ usePrecision }) => usePrecision,
        ({ divisor, price }) => Math.round((price / divisor) * 100.0) / 100.0,
    ),
    opticalPriceRoundingRule(
        // round optical price up to integer
        () => true,
        ({ divisor, price }) =>
            Math.ceil(Math.floor((price * 100) / divisor) / 100),
    ),
];

const recurrenceTerms = {
    [Commitment.YEAR]: {
        [Term.MONTHLY]: RecurrenceTerm.MONTH,
        [Term.ANNUAL]: RecurrenceTerm.YEAR,
    },
    [Commitment.MONTH]: {
        [Term.MONTHLY]: RecurrenceTerm.MONTH,
    },
};

/**
 * @param { string} formatString
 * @param { string } currencySymbol
 */
export const currencyIsFirstChar = (formatString, currencySymbol) =>
    formatString.indexOf(`'${currencySymbol}'`) === 0;

// Below implementation assumes that general numberMask start with `#` and end with `0` and decimal parts are only using `0`s.
// The return result should always contain both integer and decimal delimiters.
/**
 * @param { string } formatString
 * @param { boolean } usePrecision
 * @returns { string }
 */
const extractNumberMask = (formatString, usePrecision = true) => {
    let numberMask = formatString.replace(/'.*?'/, '').trim();
    const decimalsDelimiter = findDecimalsDelimiter(numberMask);
    const hasDecimalDelimiter = !!decimalsDelimiter;

    if (!hasDecimalDelimiter) {
        // Append the decimal delimiter to the string format `#.*0`. `$&` means the matched regex string.
        // As the formatString could be container non-symbol like `A #,##0.00 B` so using regex here.
        numberMask = numberMask.replace(
            /\s?(#.*0)(?!\s)?/,
            '$&' + getPossibleDecimalsDelimiter(formatString),
        );
    } else if (!usePrecision) {
        // Trim the 0s after the decimalsDelimiter. `#,##0.00` will become `#,##0.`
        numberMask = numberMask.replace(/[,\.]0+/, decimalsDelimiter);
    }

    return numberMask;
};

/**
 * Extracts the currency symbol from the specified format string and returns the
 * currency symbol along with other values indicating how it is to be displayed
 * (for example, so that it can be inserted into markup correctly)
 * @param formatString The currency format string (for example, "'US$ '#,##0.00")
 * @returns { {
 *  currencySymbol: string;
 *  isCurrencyFirst: boolean;
 *  hasCurrencySpace: boolean;
 * } }
 */
const getCurrencySymbolDetails = (formatString) => {
    const currencySymbol = findCurrencySymbol(formatString);
    const isCurrencyFirst = currencyIsFirstChar(formatString, currencySymbol);
    const formatStringWithoutSymbol = formatString.replace(/'.*?'/, '');
    const hasCurrencySpace =
        SPACE_START_PATTERN.test(formatStringWithoutSymbol) ||
        SPACE_END_PATTERN.test(formatStringWithoutSymbol);
    return { currencySymbol, isCurrencyFirst, hasCurrencySpace };
};

/**
 * Converts the spaces around the text to non-breaking spaces.
 * @param {string} text
 * @returns {string}
 */
const makeSpacesAroundNonBreaking = (text) => {
    return text
        .replace(SPACE_START_PATTERN, NBSP)
        .replace(SPACE_END_PATTERN, NBSP);
};

// When there is one delimiter in the formatString, it would be considered as a decimal delimiter by the library 'number-format.js' used in the package.
// But Adobe system would expect that only delimiter (used between #) be integer delimiter.
// This method determines what should be the decimal delimiter by checking the only (integer) delimiter.
// It should be called when findDecimalsDelimiter function couldn't find out a decimal delimiter.
// Note: This is based on the assumption that integer delimiter is used between `#`.
/**
 * @param { string } formatString
 * @returns { string }
 */
const getPossibleDecimalsDelimiter = (formatString) =>
    formatString.match(/#(.?)#/)?.[1] === DECIMAL_POINT
        ? DECIMAL_COMMA
        : DECIMAL_POINT;

/**
 * @param { string } formatString
 * @returns { string }
 */
const findCurrencySymbol = (formatString) =>
    formatString.match(/'(.*?)'/)?.[1] ?? '';

// This is based on the assumption that decimal delimiter is used between `0`
/**
 * @param { string } formatString
 * @returns { string }
 */
const findDecimalsDelimiter = (formatString) =>
    formatString.match(/0(.?)0/)?.[1] ?? '';

// Utilities, specific to tacocat needs.

/**
 * Formats a price according to the specified format string and currency rules.
 *
 * @param {object} options - The formatting options
 * @param {string} options.formatString - The currency format string (e.g., "'US$ '#,##0.00")
 * @param {number} options.price - The price value to format
 * @param {boolean} options.usePrecision - Whether to include decimal precision in the formatted price
 * @param {boolean} [options.isIndianPrice=false] - Whether to use Indian locale-specific formatting
 * @param {string} recurrenceTerm - The recurrence term (MONTH or YEAR) for the price
 * @param {function} [transformPrice=(price) => price] - Optional function to transform the price before formatting
 * @returns {{
 *   accessiblePrice: string,
 *   currencySymbol: string,
 *   decimals: string,
 *   decimalsDelimiter: string,
 *   hasCurrencySpace: boolean,
 *   integer: string,
 *   isCurrencyFirst: boolean,
 *   recurrenceTerm: string
 * }} Formatted price object containing the accessible price string and formatting details
 *
 */
function formatPrice(
    { formatString, price, usePrecision, isIndianPrice = false },
    recurrenceTerm,
    transformPrice = (formattedPrice) => formattedPrice,
) {
    const { currencySymbol, isCurrencyFirst, hasCurrencySpace } =
        getCurrencySymbolDetails(formatString);
    const decimalsDelimiter = usePrecision
        ? findDecimalsDelimiter(formatString)
        : '';
    const numberMask = extractNumberMask(formatString, usePrecision);
    const fractionDigits = usePrecision ? 2 : 0;
    const transformedPrice = transformPrice(price, { currencySymbol });
    const formattedPrice = isIndianPrice
        ? transformedPrice.toLocaleString('hi-IN', {
              minimumFractionDigits: fractionDigits,
              maximumFractionDigits: fractionDigits,
          })
        : formatNumber(numberMask, transformedPrice);
    const decimalIndex = usePrecision
        ? formattedPrice.lastIndexOf(decimalsDelimiter)
        : formattedPrice.length;
    const integer = formattedPrice.substring(0, decimalIndex);
    const decimals = formattedPrice.substring(decimalIndex + 1);
    const accessiblePrice = formatString
        .replace(/'.*?'/, 'SYMBOL')
        .replace(/#.*0/, formattedPrice)
        .replace(/SYMBOL/, currencySymbol);
    return {
        accessiblePrice,
        currencySymbol,
        decimals,
        decimalsDelimiter,
        hasCurrencySpace,
        integer,
        isCurrencyFirst,
        recurrenceTerm,
    };
}

/**
 * Formats optical price (as if it was billed monthly).
 * @param { import('./types').PriceData } data
 */
const formatOpticalPrice = (data) => {
    const { commitment, term, usePrecision } = data;
    const divisor = opticalPriceDivisors[term] ?? 1;
    return formatPrice(
        data,
        divisor > 1
            ? RecurrenceTerm.MONTH
            : recurrenceTerms[commitment]?.[term],
        (price) => {
            const priceData = {
                divisor,
                price,
                usePrecision,
            };
            const { round } = opticalPriceRoundingRules.find(({ accept }) =>
                accept(priceData),
            );
            if (!round)
                throw new Error(
                    `Missing rounding rule for: ${JSON.stringify(priceData)}`,
                );
            return round(priceData);
        },
    );
};

/**
 * Formats regular price.
 * @param { import('./types').PriceData } data
 */
const formatRegularPrice = ({ commitment, term, ...data }) =>
    formatPrice(data, recurrenceTerms[commitment]?.[term]);

/**
 * Creates a function that calculates the annual price with promotion applied.
 *
 * @param {object} data - The data object containing price and priceWithoutDiscount
 * @returns {function(number): number} A function that takes a monthly price and returns the calculated annual price with promotion
 *
 */
const formatAnnualPrice = (data) => {
    const {
        commitment,
        instant,
        price,
        originalPrice,
        priceWithoutDiscount,
        promotion,
        quantity = 1,
        term,
    } = data;
    if (commitment === Commitment.YEAR && term === Term.MONTHLY) {
        if (!promotion) {
            return formatPrice(data, RecurrenceTerm.YEAR, getAnnualPrice);
        }
        const { displaySummary: { outcomeType, duration } = {} } = promotion;
        switch (outcomeType) {
            case 'PERCENTAGE_DISCOUNT': {
                if (isPromotionActive(promotion, instant, quantity)) {
                    const durationInMonths = parseInt(
                        duration.replace('P', '').replace('M', ''),
                    );
                    if (isNaN(durationInMonths)) return getAnnualPrice(price);
                    const discountPrice = originalPrice * durationInMonths;
                    const regularPrice =
                        priceWithoutDiscount * (12 - durationInMonths);
                    const totalPrice =
                        Math.round((discountPrice + regularPrice) * 100) / 100;
                    return formatPrice(
                        { ...data, price: totalPrice },
                        RecurrenceTerm.YEAR,
                    );
                }
            }
            default:
                return formatPrice(data, RecurrenceTerm.YEAR, () =>
                    getAnnualPrice(priceWithoutDiscount ?? price),
                );
        }
    }
    return formatPrice(data, recurrenceTerms[commitment]?.[term]);
};

export {
    formatOpticalPrice,
    formatRegularPrice,
    formatAnnualPrice,
    makeSpacesAroundNonBreaking,
    isPromotionActive,
};

/* c8 ignore start */
'use strict';

const maskRegex = /[0-9\-+#]/;
const notMaskRegex = /[^\d\-+#]/g;

function getIndex(mask) {
    return mask.search(maskRegex);
}

function processMask(mask = '#.##') {
    const maskObj = {};
    const len = mask.length;
    const start = getIndex(mask);
    maskObj.prefix = start > 0 ? mask.substring(0, start) : '';

    // Reverse string: not an ideal method if there are surrogate pairs
    const end = getIndex(mask.split('').reverse().join(''));
    const offset = len - end;
    const substr = mask.substring(offset, offset + 1);
    // Add 1 to offset if mask has a trailing decimal/comma
    const indx = offset + (substr === '.' || substr === ',' ? 1 : 0);
    maskObj.suffix = end > 0 ? mask.substring(indx, len) : '';

    maskObj.mask = mask.substring(start, indx);
    maskObj.maskHasNegativeSign = maskObj.mask.charAt(0) === '-';
    maskObj.maskHasPositiveSign = maskObj.mask.charAt(0) === '+';

    // Search for group separator & decimal; anything not digit,
    // not +/- sign, and not #
    let result = maskObj.mask.match(notMaskRegex);
    // Treat the right most symbol as decimal
    maskObj.decimal = (result && result[result.length - 1]) || '.';
    // Treat the left most symbol as group separator
    maskObj.separator = (result && result[1] && result[0]) || ',';

    // Split the decimal for the format string if any
    result = maskObj.mask.split(maskObj.decimal);
    maskObj.integer = result[0];
    maskObj.fraction = result[1];
    return maskObj;
}

function processValue(value, maskObj, options) {
    let isNegative = false;
    const valObj = {
        value,
    };
    if (value < 0) {
        isNegative = true;
        // Process only abs(), and turn on flag.
        valObj.value = -valObj.value;
    }

    valObj.sign = isNegative ? '-' : '';

    // Fix the decimal first, toFixed will auto fill trailing zero.
    valObj.value = Number(valObj.value).toFixed(
        maskObj.fraction && maskObj.fraction.length,
    );
    // Convert number to string to trim off *all* trailing decimal zero(es)
    valObj.value = Number(valObj.value).toString();

    // Fill back any trailing zero according to format
    // look for last zero in format
    const posTrailZero = maskObj.fraction && maskObj.fraction.lastIndexOf('0');
    let [valInteger = '0', valFraction = ''] = valObj.value.split('.');
    if (!valFraction || (valFraction && valFraction.length <= posTrailZero)) {
        valFraction =
            posTrailZero < 0
                ? ''
                : Number('0.' + valFraction)
                      .toFixed(posTrailZero + 1)
                      .replace('0.', '');
    }

    valObj.integer = valInteger;
    valObj.fraction = valFraction;
    addSeparators(valObj, maskObj);

    // Remove negative sign if result is zero
    if (valObj.result === '0' || valObj.result === '') {
        // Remove negative sign if result is zero
        isNegative = false;
        valObj.sign = '';
    }

    if (!isNegative && maskObj.maskHasPositiveSign) {
        valObj.sign = '+';
    } else if (isNegative && maskObj.maskHasPositiveSign) {
        valObj.sign = '-';
    } else if (isNegative) {
        valObj.sign =
            options && options.enforceMaskSign && !maskObj.maskHasNegativeSign
                ? ''
                : '-';
    }

    return valObj;
}

function addSeparators(valObj, maskObj) {
    valObj.result = '';
    // Look for separator
    const szSep = maskObj.integer.split(maskObj.separator);
    // Join back without separator for counting the pos of any leading 0
    const maskInteger = szSep.join('');

    const posLeadZero = maskInteger && maskInteger.indexOf('0');
    if (posLeadZero > -1) {
        while (valObj.integer.length < maskInteger.length - posLeadZero) {
            valObj.integer = '0' + valObj.integer;
        }
    } else if (Number(valObj.integer) === 0) {
        valObj.integer = '';
    }

    // Process the first group separator from decimal (.) only, the rest ignore.
    // get the length of the last slice of split result.
    const posSeparator = szSep[1] && szSep[szSep.length - 1].length;
    if (posSeparator) {
        const len = valObj.integer.length;
        const offset = len % posSeparator;
        for (let indx = 0; indx < len; indx++) {
            valObj.result += valObj.integer.charAt(indx);
            // -posSeparator so that won't trail separator on full length
            if (
                !((indx - offset + 1) % posSeparator) &&
                indx < len - posSeparator
            ) {
                valObj.result += maskObj.separator;
            }
        }
    } else {
        valObj.result = valObj.integer;
    }

    valObj.result +=
        maskObj.fraction && valObj.fraction
            ? maskObj.decimal + valObj.fraction
            : '';
    return valObj;
}

function formatNumber(mask, value, options = {}) {
    if (!mask || isNaN(Number(value))) {
        // Invalid inputs
        return value;
    }

    const maskObj = processMask(mask);
    const valObj = processValue(value, maskObj, options);
    return maskObj.prefix + valObj.sign + valObj.result + maskObj.suffix;
}

// Milo commerce tests only support ESM imports/exports (no CJS)
export default formatNumber;
/* c8 ignore stop */

import {
    escapeHtml,
    isObject,
    isNumber,
    isString,
    toBoolean,
    createLog,
} from '@dexter/tacocat-core';
import IntlMessageFormat from 'intl-messageformat';
import {
    formatOpticalPrice,
    formatRegularPrice,
    formatAnnualPrice,
    makeSpacesAroundNonBreaking,
    isPromotionActive,
} from './utilities.js';

export const defaultLiterals = {
    recurrenceLabel:
        '{recurrenceTerm, select, MONTH {/mo} YEAR {/yr} other {}}',
    recurrenceAriaLabel:
        '{recurrenceTerm, select, MONTH {per month} YEAR {per year} other {}}',
    perUnitLabel: '{perUnit, select, LICENSE {per license} other {}}',
    perUnitAriaLabel: '{perUnit, select, LICENSE {per license} other {}}',
    freeLabel: 'Free',
    freeAriaLabel: 'Free',
    taxExclusiveLabel:
        '{taxTerm, select, GST {excl. GST} VAT {excl. VAT} TAX {excl. tax} IVA {excl. IVA} SST {excl. SST} KDV {excl. KDV} other {}}',
    taxInclusiveLabel:
        '{taxTerm, select, GST {incl. GST} VAT {incl. VAT} TAX {incl. tax} IVA {incl. IVA} SST {incl. SST} KDV {incl. KDV} other {}}',
    alternativePriceAriaLabel: 'Alternatively at',
    strikethroughAriaLabel: 'Regularly at',
    planTypeLabel: '{planType, select, ABM {Annual, billed monthly} other {}}',
};

const log = createLog('ConsonantTemplates/price');

export const htmlPattern = /<\/?[^>]+(>|$)/g;

export const cssClassNames = {
    container: 'price',
    containerOptical: 'price-optical',
    containerStrikethrough: 'price-strikethrough',
    containerPromoStrikethrough: 'price-promo-strikethrough',
    containerAlternative: 'price-alternative',
    containerAnnual: 'price-annual',
    containerAnnualPrefix: 'price-annual-prefix',
    containerAnnualSuffix: 'price-annual-suffix',
    disabled: 'disabled',
    currencySpace: 'price-currency-space',
    currencySymbol: 'price-currency-symbol',
    decimals: 'price-decimals',
    decimalsDelimiter: 'price-decimals-delimiter',
    integer: 'price-integer',
    recurrence: 'price-recurrence',
    taxInclusivity: 'price-tax-inclusivity',
    unitType: 'price-unit-type',
};

export const literalKeys = {
    perUnitLabel: 'perUnitLabel',
    perUnitAriaLabel: 'perUnitAriaLabel',
    recurrenceLabel: 'recurrenceLabel',
    recurrenceAriaLabel: 'recurrenceAriaLabel',
    taxExclusiveLabel: 'taxExclusiveLabel',
    taxInclusiveLabel: 'taxInclusiveLabel',
    strikethroughAriaLabel: 'strikethroughAriaLabel',
    alternativePriceAriaLabel: 'alternativePriceAriaLabel',
};

export const WCS_TAX_DISPLAY_EXCLUSIVE = 'TAX_EXCLUSIVE';

export const renderAttributes = (attributes) =>
    isObject(attributes)
        ? Object.entries(attributes)
              .filter(
                  ([, value]) =>
                      isString(value) || isNumber(value) || value === true,
              )
              .reduce(
                  (html, [key, value]) =>
                      html +
                      ` ${key}${
                          value === true ? '' : '="' + escapeHtml(value) + '"'
                      }`,
                  '',
              )
        : '';

export const renderSpan = (
    cssClass,
    content,
    attributes,
    convertSpaces = false,
) => {
    return (
        `<span class="${cssClass}${
            content ? '' : ' ' + cssClassNames.disabled
        }"${renderAttributes(attributes)}>` +
        `${
            convertSpaces
                ? makeSpacesAroundNonBreaking(content)
                : (content ?? '')
        }</span>`
    );
};

function encodeLinks(literal) {
    literal = literal.replaceAll('</a>', '&lt;/a&gt;');

    const regex = /<a [^>]+(>|$)/g;
    const matches = literal.match(regex);
    matches?.forEach((match) => {
        const encodedMatch = match
            .replace('<a ', '&lt;a ')
            .replace('>', '&gt;');
        literal = literal.replaceAll(match, encodedMatch);
    });

    return literal;
}

function decodeLinks(literal) {
    literal = literal.replaceAll('&lt;/a&gt;', '</a>');

    const regex = /&lt;a (?!&gt;)(.*?)(&gt;|$)/g;
    const matches = literal.match(regex);
    matches?.forEach((match) => {
        const encodedMatch = match
            .replace('&lt;a ', '<a ')
            .replace('&gt;', '>');
        literal = literal.replaceAll(match, encodedMatch);
    });

    return literal;
}

export function formatLiteral(literals, locale, key, parameters) {
    let literal = literals[key];
    if (literal == undefined) {
        /* c8 ignore next 2 */
        return '';
    }
    const hasHtml = literal.includes('<');
    const hasLinks = literal.includes('<a ');
    try {
        literal = hasLinks ? encodeLinks(literal) : literal;
        literal = hasHtml ? literal.replace(htmlPattern, '') : literal;
        const formattedLiteral = new IntlMessageFormat(literal, locale).format(
            parameters,
        );
        return hasLinks ? decodeLinks(formattedLiteral) : formattedLiteral;
    } catch {
        /* c8 ignore next 2 */
        log.error('Failed to format literal:', literal);
        return '';
    }
}

function renderContainer(
    cssClass,
    {
        accessibleLabel,
        altAccessibleLabel,
        currencySymbol,
        decimals,
        decimalsDelimiter,
        hasCurrencySpace,
        integer,
        isCurrencyFirst,
        recurrenceLabel,
        perUnitLabel,
        taxInclusivityLabel,
    },
    attributes = {},
) {
    const currencyMarkup = renderSpan(
        cssClassNames.currencySymbol,
        currencySymbol,
    );
    const currencySpaceMarkup = renderSpan(
        cssClassNames.currencySpace,
        hasCurrencySpace ? '&nbsp;' : '',
    );

    let markup = '';
    if (accessibleLabel)
        markup = `<sr-only class="strikethrough-aria-label">${accessibleLabel}</sr-only>`;
    else if (altAccessibleLabel)
        markup = `<sr-only class="alt-aria-label">${altAccessibleLabel}</sr-only>`;
    if (isCurrencyFirst) markup += currencyMarkup + currencySpaceMarkup;
    markup += renderSpan(cssClassNames.integer, integer);
    markup += renderSpan(cssClassNames.decimalsDelimiter, decimalsDelimiter);
    markup += renderSpan(cssClassNames.decimals, decimals);
    if (!isCurrencyFirst) markup += currencySpaceMarkup + currencyMarkup;
    markup += renderSpan(cssClassNames.recurrence, recurrenceLabel, null, true);
    markup += renderSpan(cssClassNames.unitType, perUnitLabel, null, true);
    markup += renderSpan(
        cssClassNames.taxInclusivity,
        taxInclusivityLabel,
        true,
    );

    return renderSpan(cssClass, markup, {
        ...attributes,
    });
}

/**
 * @type { import('./types').createPriceTemplate }
 * Returns a function formatting product prices using provided options.
 */
// TODO: check WCS data elements to include: analytics, endDate, language, merchant, offerType, pricePoint, startDate
const createPriceTemplate =
    ({
        isAlternativePrice = false,
        displayOptical = false,
        displayStrikethrough = false,
        displayPromoStrikethrough = false,
        displayAnnual = false,
        instant = undefined,
    } = {}) =>
    (
        {
            country,
            displayFormatted = true,
            displayRecurrence = true,
            displayPerUnit = false,
            displayTax = false,
            language,
            literals: priceLiterals = {},
            quantity = 1,
            space = false, // add a space between price literals
            isPromoApplied = false,
        } = {},
        {
            commitment,
            offerSelectorIds,
            formatString,
            price,
            priceWithoutDiscount,
            taxDisplay,
            taxTerm,
            term,
            usePrecision,
            promotion,
        } = {},
        attributes = {},
    ) => {
        Object.entries({
            country,
            formatString,
            language,
            price,
        }).forEach(([key, value]) => {
            if (value == null) {
                /* c8 ignore next 2 */
                throw new Error(
                    `Argument "${key}" is missing for osi ${offerSelectorIds?.toString()}, country ${country}, language ${language}`,
                );
            }
        });

        const literals = {
            ...defaultLiterals,
            ...priceLiterals,
        };

        const locale = `${language.toLowerCase()}-${country.toUpperCase()}`;

        let displayPrice;

        if (promotion && !isPromoApplied && priceWithoutDiscount) {
            displayPrice =
                isAlternativePrice || displayPromoStrikethrough
                    ? price
                    : priceWithoutDiscount;
        } else if (displayStrikethrough && priceWithoutDiscount) {
            displayPrice = priceWithoutDiscount;
        } else {
            displayPrice = price;
        }

        let method = displayOptical ? formatOpticalPrice : formatRegularPrice;
        if (displayAnnual) {
            method = formatAnnualPrice;
        }
        const { accessiblePrice, recurrenceTerm, ...formattedPrice } = method({
            commitment,
            formatString,
            instant,
            isIndianPrice: country === 'IN',
            originalPrice: price,
            priceWithoutDiscount,
            price: displayOptical ? price : displayPrice,
            promotion,
            quantity,
            term,
            usePrecision,
        });

        let accessibleLabel = '',
            altAccessibleLabel = '';

        let recurrenceLabel = '';
        if (toBoolean(displayRecurrence) && recurrenceTerm) {
            recurrenceLabel = formatLiteral(
                literals,
                locale,
                literalKeys.recurrenceLabel,
                {
                    recurrenceTerm,
                },
            );
        }

        let perUnitLabel = '';
        if (toBoolean(displayPerUnit)) {
            if (space) {
                perUnitLabel += ' ';
            }
            perUnitLabel += formatLiteral(
                literals,
                locale,
                literalKeys.perUnitLabel,
                {
                    perUnit: 'LICENSE',
                },
            );
        }

        let taxInclusivityLabel = '';
        if (toBoolean(displayTax) && taxTerm) {
            if (space) {
                taxInclusivityLabel += ' ';
            }
            taxInclusivityLabel += formatLiteral(
                literals,
                locale,
                taxDisplay === WCS_TAX_DISPLAY_EXCLUSIVE
                    ? literalKeys.taxExclusiveLabel
                    : literalKeys.taxInclusiveLabel,
                { taxTerm },
            );
        }

        if (displayStrikethrough) {
            accessibleLabel = formatLiteral(
                literals,
                locale,
                literalKeys.strikethroughAriaLabel,
                {
                    strikethroughPrice: accessibleLabel,
                },
            );
        }

        if (isAlternativePrice) {
            altAccessibleLabel = formatLiteral(
                literals,
                locale,
                literalKeys.alternativePriceAriaLabel,
                {
                    alternativePrice: altAccessibleLabel,
                },
            );
        }

        let cssClass = cssClassNames.container;
        if (displayOptical) {
            cssClass += ' ' + cssClassNames.containerOptical;
        }
        if (displayStrikethrough) {
            cssClass += ' ' + cssClassNames.containerStrikethrough;
        }
        if (displayPromoStrikethrough) {
            cssClass += ' ' + cssClassNames.containerPromoStrikethrough;
        }
        if (isAlternativePrice) {
            cssClass += ' ' + cssClassNames.containerAlternative;
        }
        if (displayAnnual) {
            cssClass += ' ' + cssClassNames.containerAnnual;
        }

        if (toBoolean(displayFormatted)) {
            return renderContainer(
                cssClass,
                {
                    ...formattedPrice,
                    accessibleLabel,
                    altAccessibleLabel,
                    recurrenceLabel,
                    perUnitLabel,
                    taxInclusivityLabel,
                },
                attributes,
            );
        }
        /* c8 ignore next 26 */
        const {
            currencySymbol,
            decimals,
            decimalsDelimiter,
            hasCurrencySpace,
            integer,
            isCurrencyFirst,
        } = formattedPrice;

        const unformattedPrice = [integer, decimalsDelimiter, decimals];
        if (isCurrencyFirst) {
            // the following is a non-breaking space, don't change.
            unformattedPrice.unshift(hasCurrencySpace ? ' ' : '');
            unformattedPrice.unshift(currencySymbol);
        } else {
            // the following is a non-breaking space, don't change.
            unformattedPrice.push(hasCurrencySpace ? ' ' : '');
            unformattedPrice.push(currencySymbol);
        }
        unformattedPrice.push(
            recurrenceLabel,
            perUnitLabel,
            taxInclusivityLabel,
        );
        const content = unformattedPrice.join('');
        return renderSpan(cssClass, content, attributes);
    };

/**
 * @type { import('./types').createPromoPriceTemplate }
 * Returns a function formatting product promo prices using provided options.
 * promo price can either be regular price if discounted price and regular price are the same (not applicable
 * or outdated promotion), or concatenation of new & old prices, old being stroke through.
 */
const createPromoPriceTemplate = () => (context, value, attributes) => {
    const isPromoApplied = isPromotionActive(
        value.promotion,
        value.promotion?.displaySummary?.instant,
        Array.isArray(context.quantity)
            ? context.quantity[0]
            : context.quantity,
    );
    const displayOldPrice =
        context.displayOldPrice === undefined ||
        toBoolean(context.displayOldPrice);
    const shouldDisplayOldPrice =
        displayOldPrice &&
        value.priceWithoutDiscount &&
        value.priceWithoutDiscount != value.price &&
        (!value.promotion || isPromoApplied);
    return `${
        shouldDisplayOldPrice
            ? createPriceTemplate({
                  displayStrikethrough: true,
              })({ isPromoApplied, ...context }, value, attributes) + '&nbsp;'
            : ''
    }${createPriceTemplate({ isAlternativePrice: shouldDisplayOldPrice })({ isPromoApplied, ...context }, value, attributes)}`;
};

const createPromoPriceWithAnnualTemplate =
    () => (context, value, attributes) => {
        let { instant } = context;
        try {
            if (!instant) {
                instant = new URLSearchParams(document.location.search).get(
                    'instant',
                );
            }
            if (instant) {
                instant = new Date(instant);
            }
        } catch (e) {
            instant = undefined;
            /* ignore the error */
        }
        const isPromoApplied = isPromotionActive(
            value.promotion,
            instant,
            Array.isArray(context.quantity)
                ? context.quantity[0]
                : context.quantity,
        );
        const ctxStAnnual = {
            ...context,
            displayTax: false,
            displayPerUnit: false,
            isPromoApplied,
        };
        if (!isPromoApplied) {
            return (
                createPriceTemplate()(
                    context,
                    { ...value, price: value.priceWithoutDiscount },
                    attributes,
                ) +
                renderSpan(cssClassNames.containerAnnualPrefix, '&nbsp;(') +
                createPriceTemplate({
                    displayAnnual: true,
                    instant,
                })(
                    ctxStAnnual,
                    { ...value, price: value.priceWithoutDiscount },
                    attributes,
                ) +
                renderSpan(cssClassNames.containerAnnualSuffix, ')')
            );
        }
        const displayOldPrice =
            context.displayOldPrice === undefined ||
            toBoolean(context.displayOldPrice);
        const shouldDisplayOldPrice =
            displayOldPrice &&
            value.priceWithoutDiscount &&
            value.priceWithoutDiscount != value.price;
        return `${
            shouldDisplayOldPrice
                ? createPriceTemplate({
                      displayStrikethrough: true,
                  })(ctxStAnnual, value, attributes) + '&nbsp;'
                : ''
        }${createPriceTemplate({ isAlternativePrice: shouldDisplayOldPrice })({ isPromoApplied, ...context }, value, attributes)}${renderSpan(cssClassNames.containerAnnualPrefix, '&nbsp;(')}${createPriceTemplate(
            {
                displayAnnual: true,
                instant,
            },
        )(
            ctxStAnnual,
            value,
            attributes,
        )}${renderSpan(cssClassNames.containerAnnualSuffix, ')')}`;
    };

const createPriceWithAnnualTemplate = () => (context, value, attributes) => {
    const ctxAnnual = {
        ...context,
        displayTax: false,
        displayPerUnit: false,
    };
    return `${createPriceTemplate({ isAlternativePrice: context.displayOldPrice })(context, value, attributes)}${renderSpan(cssClassNames.containerAnnualPrefix, '&nbsp;(')}${createPriceTemplate(
        {
            displayAnnual: true,
        },
    )(
        ctxAnnual,
        value,
        attributes,
    )}${renderSpan(cssClassNames.containerAnnualSuffix, ')')}`;
};

export {
    createPriceTemplate,
    createPromoPriceTemplate,
    createPriceWithAnnualTemplate,
    createPromoPriceWithAnnualTemplate,
};

import { Defaults } from './defaults.js';
import {
    price,
    pricePromo,
    priceOptical,
    priceStrikethrough,
    pricePromoStrikethrough,
    priceAnnual,
    priceWithAnnual,
    pricePromoWithAnnual,
    priceAlternative,
    priceOpticalAlternative,
    legal,
} from './price/index.js';

import { discount } from './discount/index.js';

import {
    omitProperties,
    computePromoStatus,
    toBoolean,
} from '@dexter/tacocat-core';
import { InlinePrice } from './inline-price.js';
import { toOfferSelectorIds, toQuantity } from './utilities.js';

export function Price({ literals, providers, settings }) {
    function collectPriceOptions(overrides, placeholder = null) {
        let options = {
            country: settings.country,
            language: settings.language,
            locale: settings.locale,
            literals: { ...literals.price },
        };

        if (placeholder && providers?.price) {
            for (const provider of providers.price) {
                provider(placeholder, options);
            }
        }
        const {
            displayOldPrice,
            displayPerUnit,
            displayRecurrence,
            displayTax,
            displayPlanType,
            forceTaxExclusive,
            perpetual,
            displayAnnual,
            promotionCode,
            quantity,
            alternativePrice,
            wcsOsi,
            ...rest
        } = Object.assign(options, placeholder?.dataset ?? {}, overrides ?? {});

        options = omitProperties(
            Object.assign({
                ...options,
                ...rest,
                displayOldPrice: toBoolean(displayOldPrice),
                displayPerUnit: toBoolean(displayPerUnit),
                displayRecurrence: toBoolean(displayRecurrence),
                displayTax: toBoolean(displayTax),
                displayPlanType: toBoolean(displayPlanType),
                forceTaxExclusive: toBoolean(forceTaxExclusive),
                perpetual: toBoolean(perpetual),
                displayAnnual: toBoolean(displayAnnual),
                promotionCode:
                    computePromoStatus(promotionCode).effectivePromoCode,
                quantity: toQuantity(quantity, Defaults.quantity),
                alternativePrice: toBoolean(alternativePrice),
                wcsOsi: toOfferSelectorIds(wcsOsi),
            }),
        );

        return options;
    }

    function buildPriceHTML(offers, options) {
        if (!Array.isArray(offers) || !offers.length || !options) {
            return '';
        }
        /* c8 ignore next 20 */
        const { template } = options;
        let method;
        switch (template) {
            // TODO: use price template name constants, export them from `consonant-templates`
            case 'discount':
                method = discount;
                break;
            case 'strikethrough':
                method = priceStrikethrough;
                break;
            case 'promo-strikethrough':
                method = pricePromoStrikethrough;
                break;
            case 'annual':
                method = priceAnnual;
                break;
            case 'legal':
                method = legal;
                break;
            default:
                if (
                    options.template === 'optical' &&
                    options.alternativePrice
                ) {
                    method = priceOpticalAlternative;
                } else if (options.template === 'optical') {
                    method = priceOptical;
                } else if (
                    options.displayAnnual &&
                    offers[0].planType === 'ABM'
                ) {
                    method = options.promotionCode
                        ? pricePromoWithAnnual
                        : priceWithAnnual;
                } else if (options.alternativePrice) {
                    method = priceAlternative;
                } else {
                    method = options.promotionCode ? pricePromo : price;
                }
        }

        let [offer] = offers;
        offer = { ...offer, ...offer.priceDetails };
        return method({ ...settings, ...options }, offer);
    }

    const createInlinePrice = InlinePrice.createInlinePrice;

    return {
        InlinePrice,
        buildPriceHTML,
        collectPriceOptions,
        createInlinePrice,
    };
}

import { STATE_FAILED, FF_DEFAULTS, FF_ANNUAL_PRICE } from './constants.js';
import { createMasElement, MasElement } from './mas-element.js';
import { selectOffers, sumOffers, getService } from './utilities.js';
import { Defaults } from './defaults.js';

const INDIVIDUAL = 'INDIVIDUAL_COM';
const BUSINESS = 'TEAM_COM';
const STUDENT = 'INDIVIDUAL_EDU';
const UNIVERSITY = 'TEAM_EDU';

// countries where tax is displayed for all segments by default
const DISPLAY_ALL_TAX_COUNTRIES = [
    'AT_de',
    'AU_en',
    'BE_en',
    'BE_fr',
    'BE_nl',
    'BG_bg',
    'CH_de',
    'CH_fr',
    'CH_it',
    'CZ_cs',
    'DE_de',
    'DK_da',
    'EE_et',
    'EG_ar',
    'EG_en',
    'ES_es',
    'FI_fi',
    'FR_fr',
    'GB_en',
    'GR_el',
    'GR_en',
    'HU_hu',
    'ID_en',
    'ID_id',
    'ID_in',
    'IE_en',
    'IN_en',
    'IN_hi',
    'IT_it',
    'JP_ja',
    'LU_de',
    'LU_en',
    'LU_fr',
    'MY_en',
    'MY_ms',
    'MU_en',
    'NL_nl',
    'NO_nb',
    'NZ_en',
    'PL_pl',
    'PT_pt',
    'RO_ro',
    'SE_sv',
    'SI_sl',
    'SK_sk',
    'TH_en',
    'TH_th',
    'TR_tr',
    'UA_uk',
];

// countries where tax is displayed for some segments only by default
const DISPLAY_TAX_MAP = {
    [INDIVIDUAL]: [
        'LT_lt',
        'LV_lv',
        'NG_en',
        'SA_ar',
        'SA_en',
        'SG_en',
        'KR_ko',
        'ZA_en',
    ],
    [BUSINESS]: ['LT_lt', 'LV_lv', 'NG_en', 'CO_es', 'KR_ko', 'ZA_en'],
    [STUDENT]: ['LT_lt', 'LV_lv', 'SA_en', 'SG_en', 'SA_ar'],
    [UNIVERSITY]: ['SG_en', 'KR_ko'],
};

// For most countries where tax label is displayed the tax is included for Individuals and Students
// and excluded for Business and Universities. This is the map of TaxExclusive values for other countries
const TAX_EXCLUDED_MAP = {
    ['MU_en']: [true, true, true, true],
    ['NG_en']: [false, false, false, false],
    ['AU_en']: [false, false, false, false],
    ['JP_ja']: [false, false, false, false],
    ['NZ_en']: [false, false, false, false],
    ['TH_en']: [false, false, false, false],
    ['TH_th']: [false, false, false, false],
    ['CO_es']: [false, true, false, false],
    ['AT_de']: [false, false, false, true],
    ['SG_en']: [false, false, false, true],
    ['ZA_en']: [false, false, false, false],
};
const TAX_EXCLUDED_MAP_INDEX = [INDIVIDUAL, BUSINESS, STUDENT, UNIVERSITY];
const defaultTaxExcluded = (segment) =>
    [BUSINESS, UNIVERSITY].includes(segment);

/**
 * It returns the right tax config per locale. If both country and language are provided it will return
 * the tax config for that locale. If only country code is provided it will return the first tax config it finds
 * for that country.
 * @param {Object} map Map with tax configs per locale
 * @param {string} country country code
 * @param {string} language language code
 * @param {boolean} isArray true if map is an array, otherwise it is an object
 * @returns
 */
function getTaxConfigFromMap(map, country, language, isArray) {
    if (map[country]) return map[country];
    const locale = `${country}_${language}`;
    if (map[locale]) return map[locale];

    let result;
    if (isArray) {
        result = map.find((item) => item.startsWith(`${country}_`));
    } else {
        const resultKey = Object.keys(map).find((key) =>
            key.startsWith(`${country}_`),
        );
        result = resultKey ? map[resultKey] : null;
    }
    return result;
}

/**
 * Resolves the default value for forceTaxExclusive for the provided geo info and segments.
 * @param {string} country - uppercase country code e.g. US, AT, MX
 * @param {string} language - lowercase language code e.g. en, de, es
 * @param {string} customerSegment - customer segment: INDIVIDUAL or TEAM
 * @param {string} marketSegment - market segment: COM or EDU
 * @returns {boolean} true if price will be displayed without tax, otherwise false (default)
 */
const resolveTaxExclusive = (
    country,
    language,
    customerSegment,
    marketSegment,
) => {
    const segment = `${customerSegment}_${marketSegment}`;
    const val = getTaxConfigFromMap(TAX_EXCLUDED_MAP, country, language, false);
    if (val) {
        const index = TAX_EXCLUDED_MAP_INDEX.indexOf(segment);
        return val[index];
    }

    return defaultTaxExcluded(segment);
};

/**
 * Resolves the default value of displayTax property, for the provided geo info and segments.
 * @param {string} country - uppercase country code e.g. US, AT, MX
 * @param {string} language - lowercase language code e.g. en, de, es
 * @param {string} customerSegment - customer segment: INDIVIDUAL or TEAM
 * @param {string} marketSegment - market segment: COM or EDU
 * @returns {boolean} true if tax label will be displayed, otherwise false (default)
 */
const resolveDisplayTaxForGeoAndSegment = (
    country,
    language,
    customerSegment,
    marketSegment,
) => {
    if (getTaxConfigFromMap(DISPLAY_ALL_TAX_COUNTRIES, country, language, true))
        return true;

    const segmentConfig =
        DISPLAY_TAX_MAP[`${customerSegment}_${marketSegment}`];
    if (!segmentConfig) {
        return Defaults.displayTax;
    }

    if (getTaxConfigFromMap(segmentConfig, country, language, true)) {
        return true;
    }

    return Defaults.displayTax;
};

/**
 * Resolves default values of displayTax and forceTaxExclusive, based on provided geo info and segments extracted from offers object.
 * These values will be used when the query parameters "tax" and "exclusive" are not set in the merch link, and in OST for initial
 * values for checkboxes "Tax label" and "Include tax".
 * @param {string} country - uppercase country code e.g. US, AT, MX
 * @param {string} language - lowercase language code e.g. en, de, es
 * @param {string} customerSegment - customer segment: INDIVIDUAL or TEAM
 * @param {string} marketSegment - market segment: COM or EDU
 * @returns {Promise<{displayTax: boolean, forceTaxExclusive: boolean}>} A promise with boolean properties displayTax and forceTaxExclusive
 */
export const resolvePriceTaxFlags = async (
    country,
    language,
    customerSegment,
    marketSegment,
) => {
    const displayTax = resolveDisplayTaxForGeoAndSegment(
        country,
        language,
        customerSegment,
        marketSegment,
    );
    return {
        displayTax,
        forceTaxExclusive: displayTax
            ? resolveTaxExclusive(
                  country,
                  language,
                  customerSegment,
                  marketSegment,
              )
            : Defaults.forceTaxExclusive,
    };
};

export class InlinePrice extends HTMLSpanElement {
    static is = 'inline-price';
    static tag = 'span';
    static get observedAttributes() {
        return [
            'data-display-old-price',
            'data-display-per-unit',
            'data-display-recurrence',
            'data-display-tax',
            'data-display-plan-type',
            'data-display-annual',
            'data-perpetual',
            'data-promotion-code',
            'data-force-tax-exclusive',
            'data-template',
            'data-wcs-osi',
            'data-quantity',
        ];
    }

    static createInlinePrice(options) {
        const service = getService();
        if (!service) return null;
        const {
            displayOldPrice,
            displayPerUnit,
            displayRecurrence,
            displayTax,
            displayPlanType,
            displayAnnual,
            forceTaxExclusive,
            perpetual,
            promotionCode,
            quantity,
            alternativePrice,
            template,
            wcsOsi,
        } = service.collectPriceOptions(options);
        const element = createMasElement(InlinePrice, {
            displayOldPrice,
            displayPerUnit,
            displayRecurrence,
            displayTax,
            displayPlanType,
            displayAnnual,
            forceTaxExclusive,
            perpetual,
            promotionCode,
            quantity,
            alternativePrice,
            template,
            wcsOsi,
        });
        return element;
    }

    constructor() {
        super();
        this.handleClick = this.handleClick.bind(this);
    }

    get isInlinePrice() {
        return true;
    }

    masElement = new MasElement(this);

    attributeChangedCallback(name, _, value) {
        this.masElement.attributeChangedCallback(name, _, value);
    }

    connectedCallback() {
        this.masElement.connectedCallback();
        this.addEventListener('click', this.handleClick);
    }

    disconnectedCallback() {
        this.masElement.disconnectedCallback();
        this.removeEventListener('click', this.handleClick);
    }

    handleClick(event) {
        /* c8 ignore next 4 */
        if (event.target === this) return;
        // re-dispatch click event from the price element
        event.stopImmediatePropagation();
        this.dispatchEvent(
            new MouseEvent('click', {
                bubbles: true,
                cancelable: true,
                view: window,
            }),
        );
    }

    onceSettled() {
        return this.masElement.onceSettled();
    }

    get value() {
        return this.masElement.value;
    }

    get options() {
        return this.masElement.options;
    }

    get isFailed() {
        return this.masElement.state === STATE_FAILED;
    }

    requestUpdate(force = false) {
        return this.masElement.requestUpdate(force);
    }

    /**
     * Resolves associated osi via Wcs and renders price offer.
     * @param {Record<string, any>} overrides
     */
    async render(overrides = {}) {
        if (!this.isConnected) return false;
        const service = getService();
        if (!service) return false;
        const priceOptions = service.collectPriceOptions(overrides, this);
        const options = {
            ...service.settings,
            ...priceOptions,
        };
        if (!options.wcsOsi.length) return false;
        try {
            const version = this.masElement.togglePending({});
            this.innerHTML = '';
            // Resolve all OSI promises - if any fails, Promise.all rejects
            const offerSelectorPromises =
                service.resolveOfferSelectors(options);
            const resolvedOfferArrays = await Promise.all(
                offerSelectorPromises,
            );
            // Select best offer from each OSI, then sum them
            const selectedOffers = resolvedOfferArrays.map((offerArray) => {
                const selected = selectOffers(offerArray, options);
                return selected?.length ? selected[0] : null;
            });
            // Check if any offer selection failed
            if (selectedOffers.some((offer) => !offer)) {
                throw new Error(
                    `Failed to select offers for: ${options.wcsOsi}`,
                );
            }
            let offers = selectedOffers;
            const offer = sumOffers(selectedOffers);

            if (service.featureFlags[FF_DEFAULTS] || options[FF_DEFAULTS]) {
                if (priceOptions.displayPerUnit === undefined) {
                    options.displayPerUnit =
                        offer.customerSegment !== 'INDIVIDUAL';
                }
                // if displayTax or forceTaxExclusive is not set, we need to resolve the values based on the geo and segment
                if (
                    priceOptions.displayTax === undefined ||
                    priceOptions.forceTaxExclusive === undefined
                ) {
                    const { country, language } = options;
                    const [marketSegment = ''] = offer.marketSegments;
                    // set default value for displayTax and forceTaxExclusive if not set neither in OST nor in merch link
                    const flags = await resolvePriceTaxFlags(
                        country,
                        language,
                        offer.customerSegment,
                        marketSegment,
                    );
                    if (priceOptions.displayTax === undefined) {
                        options.displayTax =
                            flags?.displayTax || options.displayTax;
                    }
                    if (priceOptions.forceTaxExclusive === undefined) {
                        options.forceTaxExclusive =
                            flags?.forceTaxExclusive ||
                            options.forceTaxExclusive;
                    }
                    if (options.forceTaxExclusive) {
                        // Re-select offers with forceTaxExclusive applied, then re-sum
                        offers = resolvedOfferArrays.map((offerArray) => {
                            const selected = selectOffers(offerArray, options);
                            return selected?.length ? selected[0] : null;
                        });
                    }
                }
            } else {
                if (priceOptions.displayOldPrice === undefined) {
                    options.displayOldPrice = true;
                }
            }

            if (
                service.featureFlags[FF_ANNUAL_PRICE] &&
                options.displayAnnual !== false
            ) {
                options.displayAnnual = true;
            }

            // Dual-OSI discount: use individual prices for cross-offer percentage
            if (options.template === 'discount' && offers.length === 2) {
                const [discountedOffer, referenceOffer] = offers;
                const crossOffer = {
                    ...discountedOffer,
                    priceDetails: {
                        ...discountedOffer.priceDetails,
                        priceWithoutDiscount:
                            referenceOffer.priceDetails?.price,
                    },
                };
                return this.renderOffers([crossOffer], options, version);
            }

            // Sum the final offers for rendering
            const finalOffer = sumOffers(offers);
            return this.renderOffers([finalOffer], options, version);
        } catch (error) {
            this.innerHTML = '';
            throw error;
        }
    }

    // TODO: can be extended to accept array of offers and compute subtotal price
    /**
     * Renders price offer as HTML of this component
     * using consonant price template functions
     * @param {Offer[]} offers
     * @param {Record<string, any>} options
     * @param {number} version
     */
    renderOffers(offers, options, version = undefined) {
        if (!this.isConnected) return;
        const service = getService();
        if (!service) return false;
        version ??= this.masElement.togglePending();
        if (offers.length) {
            if (this.masElement.toggleResolved(version, offers, options)) {
                this.innerHTML = service.buildPriceHTML(offers, this.options);

                // Adding logic for options.alternativePrice to add <sr-only>Alternatively at</sr-only>
                const parentEl = this.closest('p, h3, div');
                if (
                    !parentEl ||
                    !parentEl.querySelector(
                        'span[data-template="strikethrough"]',
                    ) ||
                    parentEl.querySelector('.alt-aria-label')
                )
                    return true;
                const inlinePrices = parentEl?.querySelectorAll(
                    'span[is="inline-price"]',
                );
                if (
                    inlinePrices.length > 1 &&
                    inlinePrices.length ===
                        parentEl.querySelectorAll(
                            'span[data-template="strikethrough"]',
                        ).length *
                            2
                ) {
                    inlinePrices.forEach((price) => {
                        if (
                            price.dataset.template !== 'strikethrough' &&
                            price.options &&
                            !price.options.alternativePrice &&
                            !price.isFailed
                        ) {
                            price.options.alternativePrice = true;
                            price.innerHTML = service.buildPriceHTML(
                                offers,
                                price.options,
                            );
                        }
                    });
                }
                return true;
            }
        } else {
            const error = new Error(
                `Not provided: ${this.options?.wcsOsi ?? '-'}`,
            );
            if (this.masElement.toggleFailed(version, error, this.options)) {
                this.innerHTML = '';
                return true;
            }
        }
        /* c8 ignore next 1 */
        return false;
    }
}

// Define custom DOM element
if (!window.customElements.get(InlinePrice.is)) {
    window.customElements.define(InlinePrice.is, InlinePrice, {
        extends: InlinePrice.tag,
    });
}

